import java.util.PriorityQueue;
import java.util.Queue;

class MKAverage {

    public MKAverage(int m, int k) {
        this.m = m;
        this.k = k;
        this.stream = new int[m];
        this.left = k;
        this.right = k;
        this.sum = 0;
    }

    public void addElement(int num) {
        if (left == right) {
            stream[right] = num;
            sum += num;
            right++;
        } else {
            int i = right - 1;
            while (i >= left) {
                stream[i + 1] = stream[i];
                sum -= stream[i];
                i--;
            }
            stream[left] = num;
            sum += num;
            left++;
        }
        if (right > m) {
            left++;
            right++;
            sum -= stream[left - k - 1];
        }
    }

    public int calculateMKAverage() {
        if (stream.length < m) {
            return -1;
        }
        int sum = 0;
        for (int i = left; i < right; i++) {
            sum += stream[i];
        }
        return sum / (m - 2 * k);
    }

    private int m, k;
    private int[] stream;
    private int left, right;
    private int sum;
}
```

